"use client";

import { useState, useEffect } from "react";
import { fetchDashboard } from "@/lib/api";
import type { DashboardResponse } from "@/types";
import MarketOverview from "@/components/dashboard/MarketOverview";
import ThemeTrend from "@/components/dashboard/ThemeTrend";
import KeywordFeed from "@/components/dashboard/KeywordFeed";
import LoadingSpinner from "@/components/ui/LoadingSpinner";
import ErrorMessage from "@/components/ui/ErrorMessage";
import Link from "next/link";

export default function DashboardPage() {
  const [data, setData] = useState<DashboardResponse | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const load = () => {
    setLoading(true);
    setError("");
    fetchDashboard()
      .then(setData)
      .catch((e) => setError(e.message))
      .finally(() => setLoading(false));
  };

  useEffect(() => {
    load();
  }, []);

  if (loading) return <LoadingSpinner text="대시보드 로딩 중..." />;
  if (error) return <ErrorMessage message={error} onRetry={load} />;
  if (!data) return null;

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">대시보드</h1>

      {/* 테마 트렌드 (최상단) */}
      <ThemeTrend />

      {/* 시장 현황 */}
      <MarketOverview marketSummary={data.market_summary} />

      {/* 내 관심 키워드 */}
      <KeywordFeed />

      {/* 최신 뉴스 */}
      <section>
        <div className="flex justify-between items-center mb-3">
          <div>
            <h2 className="text-lg font-bold">최신 뉴스</h2>
            <p className="text-xs text-gray-400">쉽게 요약해 드려요</p>
          </div>
          <Link href="/issues" className="text-sm text-skyblue hover:underline">전체 보기</Link>
        </div>
        <div className="space-y-3">
          {data.top_news.map((n) => (
            <Link key={n.id} href={`/issues/${encodeURIComponent(n.id)}`} className="block bg-white/5 border border-white/10 rounded-xl p-4 hover:bg-white/10 transition-colors">
              <p className="font-medium">{n.title}</p>
              <p className="text-xs text-gray-400 mt-1">{n.source} &middot; {new Date(n.published_at).toLocaleDateString("ko-KR")}</p>
            </Link>
          ))}
        </div>
      </section>

      {/* 주요 정책 */}
      <section>
        <div className="flex justify-between items-center mb-3">
          <div>
            <h2 className="text-lg font-bold">주요 정책</h2>
            <p className="text-xs text-gray-400">쉽게 풀어서 설명해 드려요</p>
          </div>
          <Link href="/policy" className="text-sm text-skyblue hover:underline">전체 보기</Link>
        </div>
        <div className="space-y-3">
          {data.hot_policies.map((p) => (
            <Link key={p.id} href={`/policy/${p.id}`} className="block bg-white/5 border border-white/10 rounded-xl p-4 hover:bg-white/10 transition-colors">
              <p className="font-medium">{p.title}</p>
              <p className="text-xs text-gray-400 mt-1">{p.department}</p>
            </Link>
          ))}
        </div>
      </section>
    </div>
  );
}
